import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    closest_customer_distance = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        dist = calculate_distance(cur_truck_pos, customer_pos)
        if dist < closest_customer_distance:
            closest_customer_distance = dist
            best_node = i

    if best_node is not None:
        return best_node

    max_waiting_time = -1
    for truck_pos in all_truck_pos:
        dist = calculate_distance(cur_truck_pos, truck_pos)
        if dist > max_waiting_time:
            max_waiting_time = dist

    if max_waiting_time > 0: # truck is not at depot
        return None

    return best_node

