import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    best_node = None
    min_dist = float('inf')

    for i, customer in enumerate(unvisited_customers):
        dist_to_customer = np.linalg.norm(cur_truck_pos - customer)
        if dist_to_customer < min_dist:
            min_dist = dist_to_customer
            best_node = i

    for truck_pos in all_truck_pos:
        if np.array_equal(truck_pos, cur_truck_pos):
            continue
        for i, customer in enumerate(unvisited_customers):
            dist_to_customer = np.linalg.norm(truck_pos - customer)
            if dist_to_customer < min_dist:
                best_node = i
                return best_node

    return best_node

